const email = $input.first().json;

// Parse From field - handle string, object, and array formats from Gmail trigger
let fromRaw = '';
const rawFrom = email.from;
if (typeof rawFrom === 'string') {
  fromRaw = rawFrom;
} else if (Array.isArray(rawFrom) && rawFrom.length > 0) {
  const f = rawFrom[0];
  fromRaw = f.name ? '"' + f.name + '" <' + (f.email || '') + '>' : (f.email || String(f));
} else if (rawFrom && typeof rawFrom === 'object') {
  fromRaw = rawFrom.name ? '"' + rawFrom.name + '" <' + (rawFrom.email || '') + '>' : (rawFrom.email || String(rawFrom));
}

const fromMatch = fromRaw.match(/^"?([^"<]+)"?\s*<(.+)>$/);
const fromName = fromMatch ? fromMatch[1].trim() : fromRaw.split('@')[0];
const fromEmail = fromMatch ? fromMatch[2].trim() : fromRaw;

const subject = email.subject || 'Sin asunto';
const body = email.text || email.snippet || '';
const messageId = email.id || '';
const threadId = email.threadId || '';

// Extract To field to detect developer@yourclient.com
let toField = '';
const rawTo = email.to;
if (typeof rawTo === 'string') {
  toField = rawTo;
} else if (Array.isArray(rawTo) && rawTo.length > 0) {
  toField = rawTo.map(t => typeof t === 'string' ? t : (t.email || t.address || String(t))).join(', ');
} else if (rawTo && typeof rawTo === 'object') {
  toField = rawTo.email || rawTo.address || String(rawTo);
}
// Also check headers for delivered-to or to
if (!toField) {
  const headers = Array.isArray(email.headers) ? email.headers : [];
  const toHeader = headers.find(h => h.name && h.name.toLowerCase() === 'to');
  const deliveredTo = headers.find(h => h.name && h.name.toLowerCase() === 'delivered-to');
  toField = (toHeader ? toHeader.value : '') || (deliveredTo ? deliveredTo.value : '') || '';
}
// Check flat headers object too
if (!toField && email.headers && typeof email.headers === 'object' && !Array.isArray(email.headers)) {
  toField = email.headers.to || email.headers.To || email.headers['delivered-to'] || '';
}
const isDeveloperEmail = String(toField).toLowerCase().includes('developer@yourclient.com');

// Skip automated emails
const skipPatterns = ['noreply', 'no-reply', 'mailer-daemon', 'donotreply', 'notification', 'auto-', 'bounce', '@google.com', '@facebook.com', '@linkedin.com', 'newsletter', 'unsubscribe'];
const headers2 = Array.isArray(email.headers) ? email.headers : [];
const isAutomated = skipPatterns.some(p => fromEmail.toLowerCase().includes(p) || headers2.some(h => h.name === 'X-Mailer' && h.value && h.value.includes('automated')));

return [{
  json: {
    fromEmail,
    fromName: fromName || fromEmail,
    subject,
    body: body.substring(0, 4000),
    bodySnippet: body.substring(0, 600),
    messageId,
    threadId,
    isAutomated,
    isDeveloperEmail,
    toField: String(toField),
    toAccount: isDeveloperEmail ? 'developer' : 'info'
  }
}];

const response = $input.first().json;
const aiText = response.choices?.[0]?.message?.content || 'Error generando respuesta';
const emailData = $('Extraer Datos Email').item.json;

return [{
  json: {
    ...emailData,
    aiResponse: aiText
  }
}];

const supaResult = $input.first().json;
const approvalId = Array.isArray(supaResult) ? supaResult[0].id : supaResult.id;
const emailData = $('Extraer Respuesta IA').item.json;

const approveUrl = `https://n8n.yourdomain.com/webhook/tripath-approve-email?id=${approvalId}`;
const rejectUrl = `https://n8n.yourdomain.com/webhook/tripath-reject-email?id=${approvalId}`;

const fromLine = emailData.fromName !== emailData.fromEmail
  ? `${emailData.fromName} <${emailData.fromEmail}>`
  : emailData.fromEmail;

const text = `✉️ *Nuevo email [${emailData.toAccount}@yourclient.com]*\n\n*De:* ${fromLine}\n*Asunto:* ${emailData.subject}\n\n*Extracto:*\n${emailData.bodySnippet}\n\n---\n💬 *Respuesta propuesta:*\n${emailData.aiResponse}`;

const telegramBody = {
  chat_id: YOUR_TELEGRAM_CHAT_ID,
  text: text.substring(0, 4096),
  parse_mode: 'Markdown',
  reply_markup: {
    inline_keyboard: [[
      {text: '✅ Aprobar y enviar', url: approveUrl},
      {text: '❌ Rechazar', url: rejectUrl}
    ]]
  }
};

return [{json: {telegramBody, approvalId}}];

const roomsData = $('Obtener Habitaciones').item.json;
const emailData = $('Extraer Datos Email').item.json;

// Handle both array and object with rooms property
let allRooms = [];
if (Array.isArray(roomsData)) {
  allRooms = roomsData;
} else if (roomsData && Array.isArray(roomsData.rooms)) {
  allRooms = roomsData.rooms;
}
const availableRooms = allRooms.filter(r => r.available).slice(0, 5);

const systemPrompt = 'Eres Agente del equipo Coliving en Madrid y Alicante. Tripath alquila habitaciones en pisos compartidos. Tu tarea es generar una respuesta de email profesional, cercana y en el idioma del remitente.' +
  '\n\nHABITACIONES DISPONIBLES:\n' + JSON.stringify(availableRooms) +
  '\n\nREGLAS:\n1. Responde en el idioma del email recibido (español/inglés/etc)\n2. Sé humano y directo, no robótico\n3. Si preguntan por disponibilidad, menciona habitaciones disponibles con precio\n4. Si es una queja o consulta de inquilino, sé empático y ofrece solución\n5. Máximo 150 palabras\n6. Firma como: Agente | yourclient Coliving | bookings@yourclient.com';

const userMessage = 'Email recibido de ' + emailData.fromName + ' <' + emailData.fromEmail + '>\nAsunto: ' + emailData.subject + '\n\nContenido:\n' + emailData.body;

return [{
  json: {
    requestBody: {
      model: 'google/gemini-flash-1.5',
      messages: [
        { role: 'system', content: systemPrompt },
        { role: 'user', content: userMessage }
      ]
    }
  }
}];

const data = $input.first().json;

return [{
  json: {
    ...data,
    supabaseBody: {
      email_id: data.messageId || '',
      thread_id: data.threadId || '',
      from_email: data.fromEmail || '',
      from_name: data.fromName || '',
      subject: data.subject || '',
      body_snippet: data.bodySnippet || '',
      to_account: data.toAccount || 'info',
      gmail_credential: 'eh9Byisg0sc9krul',
      proposed_response: data.aiResponse || '',
      status: 'pending'
    }
  }
}];
